// Fisher-Yates shuffle - unbiased, unlike Array.sort(() => Math.random() - 0.5)
export function shuffle(array) {
  const copy = [...array];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy;
}

// Returns a fresh shuffled subset of the category's questions (default 10 -
// a normal round length), each with its own answers shuffled too and
// `correct` re-pointed at the new position. Never mutates questionBank.
export function prepareQuestions(category, count = 10) {
  const original = questionBank[category] || [];
  const shuffled = shuffle(original).slice(0, count);
  return shuffled.map((q) => {
    const correctAnswer = q.answers[q.correct];
    const newAnswers = shuffle(q.answers);
    return {
      ...q,
      answers: newAnswers,
      correct: newAnswers.indexOf(correctAnswer),
    };
  });
}
